const localeCodeByLowerCase = new Map(supportedLocales.map(locale => [locale.code.toLowerCase(), locale.code]));
const localeAliases = new Map([
  ['zh', 'zh-Hans'], ['zh-cn', 'zh-Hans'], ['zh-sg', 'zh-Hans'], ['cmn', 'zh-Hans'],
  ['pt-br', 'pt'], ['pt-pt', 'pt'], ['ar-eg', 'arz'], ['pcm-ng', 'pcm'],
]);

export function resolveLocale(value, fallback = defaultLocale) {
  if (!value) return fallback;
  const candidate = String(value).trim().replaceAll('_', '-').toLowerCase();
  if (!candidate) return fallback;
  if (localeCodeByLowerCase.has(candidate)) return localeCodeByLowerCase.get(candidate);
  if (localeAliases.has(candidate)) return localeAliases.get(candidate);
  const base = candidate.split('-')[0];
  if (localeCodeByLowerCase.has(base)) return localeCodeByLowerCase.get(base);
  if (localeAliases.has(base)) return localeAliases.get(base);
  return fallback;
}

export function getMessages(locale) {
  return messages[resolveLocale(locale)] || messages[defaultLocale];
}

const defaultMessageKeys = Object.keys(messages[defaultLocale]).sort().join('\n');
for (const locale of supportedLocales) {
  const localeMessages = messages[locale.code];
  if (!localeMessages) throw new Error(`Missing messages for ${locale.code}.`);
  if (Object.keys(localeMessages).sort().join('\n') !== defaultMessageKeys) throw new Error(`Message keys differ for ${locale.code}.`);
  if (!Array.isArray(localeMessages.heroSteps) || localeMessages.heroSteps.length !== 4) throw new Error(`Hero steps differ for ${locale.code}.`);
}
